import sys
from functools import cmp_to_key

def custom_compare(a, b):
    for j in range(len(a)):
        if a[j] != b[j]:
            if j % 2 == 0:  # 0-based even (1-based odd)
                return -1 if a[j] < b[j] else 1
            else:  # 0-based odd (1-based even)
                return -1 if a[j] > b[j] else 1
    return 0

def sort_books(n, m, books):
    indexed_books = [(books[i], i + 1) for i in range(n)]
    indexed_books.sort(key=cmp_to_key(lambda x, y: custom_compare(x[0], y[0])))
    return [index for _, index in indexed_books]

def main():
    input = sys.stdin.read
    data = input().split()

    n = int(data[0])
    m = int(data[1])

    books = data[2:2 + n]

    result = sort_books(n, m, books)
    print(' '.join(map(str, result)))

if __name__ == "__main__":
    main()

