def min_operations_to_portal(t, test_cases):
    results = []

    for case in test_cases:
        n, m, grid = case
        min_operations = float('inf')

        # Iterate over all possible top-left corners of sub-rectangles
        for i in range(n - 4):
            for j in range(m - 3):
                # Try all possible sizes of sub-rectangles starting from (i, j)
                for a in range(5, n - i + 1):
                    for b in range(4, m - j + 1):
                        # Calculate the cost to transform the sub-rectangle into a portal
                        cost = 0
                        # Top and bottom borders
                        for x in range(j + 1, j + b - 1):
                            if grid[i][x] != '1':
                                cost += 1
                            if grid[i + a - 1][x] != '1':
                                cost += 1
                        # Left and right borders
                        for y in range(i + 1, i + a - 1):
                            if grid[y][j] != '1':
                                cost += 1
                            if grid[y][j + b - 1] != '1':
                                cost += 1
                        # Interior
                        for y in range(i + 1, i + a - 1):
                            for x in range(j + 1, j + b - 1):
                                if grid[y][x] != '0':
                                    cost += 1
                        # Update minimum operations
                        min_operations = min(min_operations, cost)

        results.append(min_operations)

    return results

