def determine_winner(N, A):
    left, right = 0, N - 1
    last = -1
    isAliceTurn = True

    while left <= right:
        if A[left] > last and A[right] > last:
            if A[left] < A[right]:
                last = A[left]
                left += 1
            else:
                last = A[right]
                right -= 1
        elif A[left] > last:
            last = A[left]
            left += 1
        elif A[right] > last:
            last = A[right]
            right -= 1
        else:
            break
        isAliceTurn = not isAliceTurn

    return "Bob" if isAliceTurn else "Alice"

