def balance_ab_ba(t, test_cases):
    results = []
    for s in test_cases:
        countAB = 0
        countBA = 0
        n = len(s)

        # Count occurrences of "ab" and "ba"
        for i in range(n - 1):
            if s[i] == 'a' and s[i + 1] == 'b':
                countAB += 1
            elif s[i] == 'b' and s[i + 1] == 'a':
                countBA += 1

        # If counts are already equal, no change is needed
        if countAB == countBA:
            results.append(s)
        else:
            # We need to make a change to balance the counts
            # If countAB > countBA, change the first "ab" to "bb"
            # If countBA > countAB, change the first "ba" to "aa"
            s_list = list(s)  # Convert string to list for easy manipulation
            if countAB > countBA:
                # Find the first "ab" and change it to "bb"
                for i in range(n - 1):
                    if s_list[i] == 'a' and s_list[i + 1] == 'b':
                        s_list[i] = 'b'
                        break
            else:
                # Find the first "ba" and change it to "aa"
                for i in range(n - 1):
                    if s_list[i] == 'b' and s_list[i + 1] == 'a':
                        s_list[i] = 'a'
                        break

            results.append(''.join(s_list))

    return results

