    import sys
    input = sys.stdin.read
    data = input().split()

    index = 0
    t = int(data[index])
    index += 1
    results = []

    for _ in range(t):
        S = data[index]
        index += 1
        T = data[index]
        index += 1

        # Count occurrences of each character in S
        count = {}
        for char in S:
            if char in count:
                count[char] += 1
            else:
                count[char] = 1

        # Sort the characters in S
        sorted_S = sorted(S)

        # If T is a permutation of "abc", we need to handle it specially
        if all(c in count for c in "abc"):
            a_count = count.get('a', 0)
            b_count = count.get('b', 0)
            c_count = count.get('c', 0)

            # Create a new order for 'a', 'b', 'c' to avoid T as a subsequence
            if T == "abc":
                new_order = 'a' * a_count + 'c' * c_count + 'b' * b_count
            elif T == "acb":
                new_order = 'a' * a_count + 'b' * b_count + 'c' * c_count
            elif T == "bac":
                new_order = 'b' * b_count + 'a' * a_count + 'c' * c_count
            elif T == "bca":
                new_order = 'b' * b_count + 'c' * c_count + 'a' * a_count
            elif T == "cab":
                new_order = 'c' * c_count + 'a' * a_count + 'b' * b_count
            elif T == "cba":
                new_order = 'c' * c_count + 'b' * b_count + 'a' * a_count

            # Collect the rest of the characters
            rest = [char for char in sorted_S if char not in "abc"]

            # Combine the new order with the rest
            result = new_order + ''.join(rest)
        else:
            # If not all 'a', 'b', 'c' are present, just return the sorted S
            result = ''.join(sorted_S)

        results.append(result)

    for res in results:
        print(res)

