    results = []
    for s in test_cases:
        n = len(s)
        if s.count('N') == 0:
            results.append("YES")
        elif s.count('E') == 0:
            if n % 2 == 0:
                results.append("YES")
            else:
                results.append("NO")
        else:
            # Check for consistency in mixed cases
            # We need to ensure that there are no contradictions
            # We can use a union-find approach to manage connected components
            parent = list(range(n))

            def find(x):
                if parent[x] != x:
                    parent[x] = find(parent[x])
                return parent[x]

            def union(x, y):
                rootX = find(x)
                rootY = find(y)
                if rootX != rootY:
                    parent[rootY] = rootX

            # Union all 'E' connections
            for i in range(n):
                if s[i] == 'E':
                    union(i, (i + 1) % n)

            # Check 'N' connections for contradictions
            consistent = True
            for i in range(n):
                if s[i] == 'N':
                    if find(i) == find((i + 1) % n):
                        consistent = False
                        break

            if consistent:
                results.append("YES")
            else:
                results.append("NO")

    return results

